	ssize_t n;
	char buf[] = "Some content for a new file";
	mongoc_iovec_t iov = { .iov_base = buf, .iov_len = sizeof buf };

	mongoc_init();

	client = mongoc_client_new("mongodb://127.0.0.1");
	BSON_ASSERT(client);
