	BSON_ASSERT(mongoc_gridfs_file_save(file)); // Save file
	BSON_ASSERT(mongoc_gridfs_file_remove(file, &error)); // Remove file

	// Now the issue ....

	// mongoc_gridfs_file_readv() fails as expected
